import { describe, it, expect } from 'vitest';
import {
  parseDebtComment,
  scanTextForDebt,
  formatDebtMarker,
  DEBT_TOKEN,
} from '../../lib/debt-markers.js';

// The literal marker token, assembled here too so this test file never
// hard-codes a substring that a repo grep would treat as a real marker.
const T = DEBT_TOKEN; // "ork-debt"

describe('parseDebtComment', () => {
  it('parses a full marker (choice + upgrade + trigger)', () => {
    const r = parseDebtComment(`// ${T}: session cookies, upgrade to JWT, when a 2nd service is added`);
    expect(r).not.toBeNull();
    expect(r?.choice).toBe('session cookies');
    expect(r?.upgrade).toBe('JWT');
    expect(r?.trigger).toBe('a 2nd service is added');
  });

  it('parses choice + upgrade with no trigger', () => {
    const r = parseDebtComment(`// ${T}: in-memory Map, upgrade to Redis`);
    expect(r?.choice).toBe('in-memory Map');
    expect(r?.upgrade).toBe('Redis');
    expect(r?.trigger).toBeUndefined();
  });

  it('parses a bare choice (no upgrade, no trigger)', () => {
    const r = parseDebtComment(`# ${T}: skip pagination for now`);
    expect(r?.choice).toBe('skip pagination for now');
    expect(r?.upgrade).toBeUndefined();
    expect(r?.trigger).toBeUndefined();
  });

  it('supports # -- ; and block-comment leaders', () => {
    expect(parseDebtComment(`-- ${T}: raw SQL, upgrade to an ORM`)?.upgrade).toBe('an ORM');
    expect(parseDebtComment(`; ${T}: hard-coded path`)?.choice).toBe('hard-coded path');
    expect(parseDebtComment(`/* ${T}: stub, upgrade to real impl, when tests exist */`)?.trigger).toBe('tests exist');
  });

  it('is case-insensitive on the upgrade/when keywords', () => {
    const r = parseDebtComment(`// ${T}: A, Upgrade To B, When C`);
    expect(r?.choice).toBe('A');
    expect(r?.upgrade).toBe('B');
    expect(r?.trigger).toBe('C');
  });

  it('returns null for lines with no marker', () => {
    expect(parseDebtComment('const x = 1; // just a normal comment')).toBeNull();
    expect(parseDebtComment('// TODO: not a debt marker')).toBeNull();
    expect(parseDebtComment('')).toBeNull();
  });

  it('returns null when the marker has an empty body', () => {
    expect(parseDebtComment(`// ${T}:   `)).toBeNull();
  });
});

describe('scanTextForDebt', () => {
  it('collects every marker across multiple lines', () => {
    const text = [
      'const a = 1;',
      `// ${T}: SQLite, upgrade to Postgres, when writers > 1`,
      'function f() {}',
      `# ${T}: inline send, upgrade to a queue`,
      'done',
    ].join('\n');
    const found = scanTextForDebt(text);
    expect(found).toHaveLength(2);
    expect(found[0].choice).toBe('SQLite');
    expect(found[1].choice).toBe('inline send');
  });

  it('returns an empty array when there are no markers', () => {
    expect(scanTextForDebt('line1\nline2\n')).toEqual([]);
  });
});

describe('formatDebtMarker', () => {
  it('renders choice, upgrade and trigger compactly', () => {
    expect(
      formatDebtMarker({ choice: 'SQLite', upgrade: 'Postgres', trigger: 'writers > 1', raw: '' }),
    ).toBe('SQLite -> Postgres (when writers > 1)');
  });

  it('flags a missing trigger as just a TODO', () => {
    expect(formatDebtMarker({ choice: 'X', upgrade: 'Y', raw: '' })).toBe('X -> Y (no trigger: just a TODO)');
  });
});
